#ifndef JUDGE_H
#define JUDGE_H

#include "read_support.hpp"
#include <vector>
#include <cmath>

using namespace std;


void get_center_of_mass(const IMAGE_T& img, double& cy, double& cx) {
    double total = 0;
    cy = 0; cx = 0;
    for (int i = 0; i < 28; ++i) {
        for (int j = 0; j < 28; ++j) {
            total += img[i][j];
            cy += i * img[i][j];
            cx += j * img[i][j];
        }
    }
    if (total > 0) {
        cy /= total;
        cx /= total;
    } else {
        cy = 14;
        cx = 14;
    }
}

IMAGE_T center_by_mass(const IMAGE_T& img) {
    double cy, cx;
    get_center_of_mass(img, cy, cx);
    int shift_y = round(14 - cy);
    int shift_x = round(14 - cx);
    
    IMAGE_T shifted(28, vector<double>(28, 0.0));
    for (int i = 0; i < 28; ++i) {
        for (int j = 0; j < 28; ++j) {
            int ni = i + shift_y;
            int nj = j + shift_x;
            if (ni >= 0 && ni < 28 && nj >= 0 && nj < 28) {
                shifted[ni][nj] = img[i][j];
            }
        }
    }
    return shifted;
}

int judge(IMAGE_T &image) {
    IMAGE_T centered = center_by_mass(image);
    
    vector<double> features;
    for (int r = 0; r < 28; ++r) {
        for (int c = 0; c < 28; ++c) {
            features.push_back(centered[r][c]);
        }
    }
    features.push_back(1.0); // bias
    
    int best_c = 0;
    double max_logit = -1e9;
    
    for (int c = 0; c < 10; ++c) {
        double logit = 0;
        for (int f = 0; f < 785; ++f) {
            logit += weights[c][f] * features[f];
        }
        if (logit > max_logit) {
            max_logit = logit;
            best_c = c;
        }
    }
    
    return best_c;
}

#endif
